class TradingAPI {
    static let shared = TradingAPI()
    private let session = URLSession.shared
    private let monitor = NWPathMonitor()
    private let queue = DispatchQueue(label: "NetworkMonitor")
    private var isNetworkAvailable = true
    
    private init() {
        monitor.pathUpdateHandler = { [weak self] path in
            DispatchQueue.main.async {
                self?.isNetworkAvailable = path.status == .satisfied
            }
        }
        monitor.start(queue: queue)
    }
    
    func fetchStocks(symbols: [String], completion: @escaping (Result<[Stock], Error>) -> Void) {
        guard isNetworkAvailable else {
            completion(.failure(NetworkError.noConnection))
            return
        }
        
        let urlString = "https://api.example.com/stocks?symbols=\(symbols.joined(separator: ","))"
        guard let url = URL(string: urlString) else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(APIKeyManager.shared.token)", forHTTPHeaderField: "Authorization")
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let stocks = try JSONDecoder().decode([Stock].self, from: data)
                completion(.success(stocks))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func executeTrade(_ trade: Trade, completion: @escaping (Result<Trade, Error>) -> Void) {
        guard isNetworkAvailable else {
            completion(.failure(NetworkError.noConnection))
            return
        }
        
        let urlString = "https://api.example.com/trades"
        guard let url = URL(string: urlString) else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("Bearer \(APIKeyManager.shared.token)", forHTTPHeaderField: "Authorization")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            let jsonData = try JSONEncoder().encode(trade)
            request.httpBody = jsonData
        } catch {
            completion(.failure(error))
            return
        }
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let executedTrade = try JSONDecoder().decode(Trade.self, from: data)
                completion(.success(executedTrade))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
}

enum NetworkError: Error {
    case noConnection
    case invalidURL
    case noData
}

