class PortfolioManager {
    static let shared = PortfolioManager()
    private var portfolio: [PortfolioItem] = []
    private let userDefaults = UserDefaults.standard
    private let portfolioKey = "PortfolioItems"
    
    private init() {
        loadPortfolio()
    }
    
    func addTrade(_ trade: Trade) {
        guard let index = portfolio.firstIndex(where: { $0.symbol == trade.symbol }) else {
            let newItem = PortfolioItem(symbol: trade.symbol, quantity: trade.quantity, averagePrice: trade.price, currentPrice: trade.price)
            portfolio.append(newItem)
            savePortfolio()
            return
        }
        
        let item = portfolio[index]
        let newQuantity = trade.type == .buy ? item.quantity + trade.quantity : item.quantity - trade.quantity
        let newAveragePrice = trade.type == .buy ? 
            ((item.averagePrice * Double(item.quantity)) + (trade.price * Double(trade.quantity))) / Double(newQuantity) : 
            item.averagePrice
        
        portfolio[index] = PortfolioItem(symbol: trade.symbol, quantity: newQuantity, averagePrice: newAveragePrice, currentPrice: trade.price)
        savePortfolio()
    }
    
    func getPortfolio() -> [PortfolioItem] {
        return portfolio
    }
    
    private func savePortfolio() {
        do {
            let data = try JSONEncoder().encode(portfolio)
            userDefaults.set(data, forKey: portfolioKey)
        } catch {
            print("Failed to save portfolio: \(error)")
        }
    }
    
    private func loadPortfolio() {
        guard let data = userDefaults.data(forKey: portfolioKey) else { return }
        do {
            portfolio = try JSONDecoder().decode([PortfolioItem].self, from: data)
        } catch {
            print("Failed to load portfolio: \(error)")
        }
    }
}

class TradeViewController: UIViewController {
    @IBOutlet weak var symbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var priceLabel: UILabel!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var sellButton: UIButton!
    @IBOutlet weak var tableView: UITableView!
    
    private var stocks: [Stock] = []
    private var portfolio: [PortfolioItem] = []
    private var selectedStock: Stock?
    private var cancellables = Set<AnyCancellable>()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupTableView()
        fetchStockData()
    }
    
    private func setupUI() {
        title = "Trading"
        buyButton.backgroundColor = .systemGreen
        sellButton.backgroundColor = .systemRed
        buyButton.setTitleColor(.white, for: .normal)
        sellButton.setTitleColor(.white, for: .normal)
    }
    
    private func setupTableView() {
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "StockCell")
    }
    
    private func fetchStockData() {
        TradingAPI.shared.fetchStocks(symbols: ["AAPL", "GOOGL", "MSFT", "TSLA", "AMZN"]) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let stocks):
                    self?.stocks = stocks
                    self?.tableView.reloadData()
                case .failure(let error):
                    print("Failed to fetch stocks: \(error)")
                }
            }
        }
    }
    
    @IBAction func buyButtonTapped(_ sender: UIButton) {
        executeTrade(type: .buy)
    }
    
    @IBAction func sellButtonTapped(_ sender: UIButton) {
        executeTrade(type: .sell)
    }
    
    private func executeTrade(type: TradeType) {
        guard let symbol = symbolTextField.text, !symbol.isEmpty,
              let quantity = Int(quantityTextField.text ?? "0"),
              let price = selectedStock?.currentPrice else {
            showAlert(message: "Please enter valid values")
            return
        }
        
        let trade = Trade(symbol: symbol, type: type, quantity: quantity, price: price, timestamp: Date())
        
        TradingAPI.shared.executeTrade(trade) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let executedTrade):
                    PortfolioManager.shared.addTrade(executedTrade)
                    self?.showAlert(message: "Trade executed successfully")
                case .failure(let error):
                    self?.showAlert(message: "Trade failed: \(error)")
                }
            }
        }
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Trade", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension TradeViewController: UITableViewDelegate, UITableViewDataSource {
